<?php
 namespace League\CommonMark; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\AbstractStringContainerBlock; use League\CommonMark\Delimiter\DelimiterStack; use League\CommonMark\Reference\ReferenceMapInterface; class InlineParserContext { private $container; private $referenceMap; private $cursor; private $delimiterStack; public function __construct(AbstractStringContainerBlock $container, ReferenceMapInterface $referenceMap) { $this->referenceMap = $referenceMap; $this->container = $container; $this->cursor = new Cursor(\trim($container->getStringContent())); $this->delimiterStack = new DelimiterStack(); } public function getContainer(): AbstractBlock { return $this->container; } public function getReferenceMap(): ReferenceMapInterface { return $this->referenceMap; } public function getCursor(): Cursor { return $this->cursor; } public function getDelimiterStack(): DelimiterStack { return $this->delimiterStack; } } 